use std::collections::BinaryHeap;

fn solve(m: i64, n: i64, waitCost: Vec<Vec<i64>>) -> i64 {
    let m = m as usize;
    let n = n as usize;
    let mut dist = vec![vec![vec![i64::MAX; 2]; n]; m];
    let mut pq = BinaryHeap::new();
    let initial_cost = (0 + 1) * (0 + 1);
    dist[0][0][1] = initial_cost;
    pq.push((initial_cost, 0, 0, 1));

    while let Some((cost, i, j, parity)) = pq.pop() {
        if i == m - 1 && j == n - 1 {
            return cost;
        }
        if cost > dist[i][j][parity] {
            continue;
        }
        if parity == 1 {
            if j + 1 < n {
                let ni = i;
                let nj = j + 1;
                let new_cost = cost + (ni + 1) * (nj + 1);
                if new_cost < dist[ni][nj][0] {
                    dist[ni][nj][0] = new_cost;
                    pq.push((new_cost, ni, nj, 0));
                }
            }
            if i + 1 < m {
                let ni = i + 1;
                let nj = j;
                let new_cost = cost + (ni + 1) * (nj + 1);
                if new_cost < dist[ni][nj][0] {
                    dist[ni][nj][0] = new_cost;
                    pq.push((new_cost, ni, nj, 0));
                }
            }
        } else {
            let new_cost = cost + waitCost[i][j];
            if new_cost < dist[i][j][1] {
                dist[i][j][1] = new_cost;
                pq.push((new_cost, i, j, 1));
            }
        }
    }
    i64::MAX
}
